var e=JSON.parse(`[{"id":"L7_1","type":"dialog","speaker":"JOHN_MASON_NULL_NULL","text":{"KOREA":"우측, 아니 좌측에서도 온다!","JPN":"右、いや左からも来るぞ！","ENG":"They’re flanking us from the right... and left too!","TWN":"不只右側，連左側也來了！"},"stage":{"bg":"SCHOOL_ABANDONED","slots":{"L":null,"C":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"YOOJIN_ALT_NULL_NULL","text":{"KOREA":"길을 뚫어야 해! 전진해야 한다고!","JPN":"なんとか突破するんだ！　前に進まなければ！","ENG":"You have to push through! We've got to keep moving!","TWN":"殺出一條路來！我們得前進啊！"},"stage":{"bg":"SCHOOL_ABANDONED","slots":{"L":null,"C":{"char_id":"YOOJIN_ALT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"YOOJIN_ALT_NULL_NULL","text":{"KOREA":"내 말 듣고 있어?! 젠장, 누구든 좀 어떻게 해 봐!!","JPN":"俺の話、聞こえてるか！？　ちくしょう、誰でもいいからなんとかしてみろよ！！","ENG":"Does anyone copy?! Come on, do something!","TWN":"有聽到我說的話嗎？！該死，不管是誰都好，快做點什麼啊！！"},"stage":{"bg":"SCHOOL_ABANDONED","slots":{"L":null,"C":{"char_id":"YOOJIN_ALT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_NULL_NULL","text":{"KOREA":"어떡할까요, 스승님?","JPN":"師匠、どうしますか？","ENG":"What should we do, Master?","TWN":"要怎麼做呢，師父？"},"stage":{"bg":"SCHOOL_ABANDONED","slots":{"L":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L14_1","type":"dialog","speaker":"HILDE_FENRIR_NULL_NULL","text":{"KOREA":"분명 나유빈이 이 근처에 숨어서 보고 있을 거다.","JPN":"きっとイチノセがこの近くに隠れて見ているはずだ。","ENG":"There’s no doubt that Yubin is in hiding somewhere nearby, watching.","TWN":"羅瑜斌肯定躲在附近，正看著這裡。"},"stage":{"bg":"SCHOOL_ABANDONED","slots":{"L":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L15_1","type":"dialog","speaker":"HILDE_FENRIR_NULL_NULL","text":{"KOREA":"놈이 언제 끼어들지 모르는 이상, 우리라도 여력을 남겨두지 않으면 위험해......","JPN":"奴がいつ割り込んでくるかわからない以上、私たちだけでも余力を残しておかねば危険だ。","ENG":"We need to conserve our forces in case he intervenes. Otherwise, it's too risky.","TWN":"只要那傢伙不插手，我們就得保留餘力，不然會很危險……"},"stage":{"bg":"SCHOOL_ABANDONED","slots":{"L":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L16_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_NULL_NULL","text":{"KOREA":"그런가요? 그럼 서윤 양을 구하긴 어렵겠네요.","JPN":"そうですか。じゃあ、シズカさんを救うのは厳しそうですね。","ENG":"Is that right? Then I guess we won’t be able to rescue Seo Yoon.","TWN":"是嗎？那要救出徐芸小姐就很困難了呢。"},"stage":{"bg":"SCHOOL_ABANDONED","slots":{"L":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L20_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_NULL_NULL","text":{"KOREA":"엇차, 위험.","JPN":"おっと、危ないな。","ENG":"Oopsie. That was close.","TWN":"哎喲，好險。"},"stage":{"bg":"SCHOOL_ABANDONED","slots":{"L":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L21_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_NULL_NULL","text":{"KOREA":"지난번에 싸웠던 일반적인 리플레이서 붕괴체들보다 강한 녀석들이네요.","JPN":"こいつら、この前戦った一般的なリプレイサー崩壊体よりも手ごわいですね。","ENG":"These guys are a lot stronger than the regular Replacer Collapsers we fought last time.","TWN":"這些傢伙比上次交手的克隆崩壞體還強呢。"},"stage":{"bg":"SCHOOL_ABANDONED","slots":{"L":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L22_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_NULL_NULL","text":{"KOREA":"아마 엘리트 변이체인 모양인데, 숫자도 그렇고 지금 알트 소대와 메이슨 씨 일행의 화력으로는......","JPN":"たぶんエリート変異体でしょうね。数の方も、今のアルト小隊やメイソンさんたちではちょっと厳しそうですね……","ENG":"They must be some sort of elite mutants. And a whole lot of them too... Not sure if the ALT Squad and Mr. Mason’s crew have enough firepower...","TWN":"大概是精英特異體吧。不過看敵人這個數量，憑目前阿爾特小隊和梅森先生一行人的火力……"},"stage":{"bg":"SCHOOL_ABANDONED","slots":{"L":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L23_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_NULL_NULL","text":{"KOREA":"하하, 요즘 직장 동료 조의금은 얼마쯤 내야 하죠?","JPN":"ははっ、最近の同僚の弔慰金は、いくら位が相場ですかね。","ENG":"Haha, do we still get the day off for employee funerals?","TWN":"哈哈，最近給職場同事的白包應該要包多少啊？"},"stage":{"bg":"SCHOOL_ABANDONED","slots":{"L":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L24_1","type":"dialog","speaker":"HILDE_FENRIR_NULL_NULL","text":{"KOREA":"......위험하다고 했지, 하지 말자고 한 적은 없다. 인정머리 없는 제자야.","JPN":"……危ないとは言ったが、やめるとは言ってないぞ。心無い弟子よ。","ENG":"I said it'd be risky. Never said anything about not rescuing her. Cold-hearted apprentice.","TWN":"……我只說很危險，又沒說不去救他們啊，你這個沒心沒肺的徒弟。"},"stage":{"bg":"SCHOOL_ABANDONED","slots":{"L":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L25_1","type":"dialog","speaker":"HILDE_FENRIR_NULL_NULL","text":{"KOREA":"아무리 그래도 차석 소대장이 죽는 걸 그냥 두고 볼 수는 없지.","JPN":"次席小隊長が命を落とすかもしれないのに、見て見ぬふりはできないだろう。","ENG":"Besides, I can’t just watch the second-in-command perish like that.","TWN":"無論如何，都不能眼睜睜地看著第二小隊的小隊長死掉。"},"stage":{"bg":"SCHOOL_ABANDONED","slots":{"L":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L26_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_NULL_NULL","text":{"KOREA":"알겠습니다. 그럼 제가 도울 테니, 스승님이 전위를.......","JPN":"了解しました。では僕が手伝いますので、師匠が前衛担当で……","ENG":"Understood. Then I’ll help if you’d start up the-","TWN":"我明白了，那我會幫助妳的，前排就交給師父……"},"stage":{"bg":"SCHOOL_ABANDONED","slots":{"L":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L28_1","type":"dialog","speaker":null,"text":{"KOREA":"크아아아아!","JPN":"うおおおおお！！","ENG":"Grooar!","TWN":"哢啊啊啊啊啊！！"},"stage":{"bg":"SCHOOL_ABANDONED","slots":{"L":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L29_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_NULL_NULL","text":{"KOREA":"......불길한 예감이 드는 소리네요?","JPN":"……この声、不吉な予感がしますね。","ENG":"That didn’t sound good.","TWN":"……這聲慘叫還真讓人有不祥的預感呢？"},"stage":{"bg":"SCHOOL_ABANDONED","slots":{"L":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}}]`);export{e as default};